const msg = $json || {};
const norm = (v) => String(v || '').replace(/\r/g, '\n').trim();
const lower = (v) => norm(v).toLowerCase();
const email = (obj) => lower(obj?.emailAddress?.address);

function htmlToText(html) {
  let t = String(html || '');
  // Remove style/script blocks
  t = t.replace(/<style[\s\S]*?<\/style>/gi, '');
  t = t.replace(/<script[\s\S]*?<\/script>/gi, '');
  // Convert table cells to spaces, rows to newlines
  t = t.replace(/<\/td>/gi, ' ').replace(/<\/tr>/gi, '\n');
  // Convert block elements to newlines
  t = t.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n').replace(/<\/div>/gi, '\n').replace(/<\/li>/gi, '\n');
  // Strip remaining tags
  t = t.replace(/<[^>]+>/g, ' ');
  // Decode HTML entities
  t = t.replace(/&nbsp;/gi, ' ').replace(/&amp;/gi, '&').replace(/&lt;/gi, '<')
       .replace(/&gt;/gi, '>').replace(/&quot;/gi, '"').replace(/&#(\d+);/g, (_, n) => String.fromCharCode(n))
       .replace(/&[a-z]+;/gi, ' ');
  // Clean whitespace
  t = t.replace(/\u00a0/g, ' ').replace(/[ \t]+/g, ' ').replace(/\n{3,}/g, '\n\n');
  return t.trim();
}

function stripThread(text, isForward) {
  if (isForward) return String(text || '').trim();
  const markers = [
    /^from:\s.+$/im, /^van:\s.+$/im, /^von:\s.+$/im,
    /^sent:\s.+$/im, /^verzonden:\s.+$/im, /^gesendet:\s.+$/im,
    /^on .+ wrote:$/im, /^op .+ schreef .+:$/im,
    /^-----\s*original message\s*-----$/im
  ];
  let r = String(text || '');
  for (const m of markers) {
    const match = r.match(m);
    if (match?.index > 10) r = r.slice(0, match.index).trim();
  }
  return r.split('\n').filter(l => !/^>+/.test(l.trim())).join('\n').trim();
}

function stripSig(text) {
  const sigs = [
    /^met vriendelijke groet/i, /^kind regards/i, /^best regards/i,
    /^mit freundlichen gr/i, /^mvg[,\s]/i, /^--\s*$/,
    /^med venlig hilsen/i
  ];
  const lines = String(text || '').split('\n');
  for (let i = 0; i < lines.length; i++) {
    if (sigs.some(re => re.test(lines[i].trim()))) return lines.slice(0, i).join('\n').trim();
  }
  return lines.join('\n').trim();
}

const subject = norm(msg.subject);
const bodyPreview = norm(msg.bodyPreview);
const bodyHtml = norm(msg.body?.content);
const bodyText = htmlToText(bodyHtml);

// Detect forwarded or replied mail
const isForward = /^(FW:|Fwd:|WG:)/i.test(subject.trim());
const isReply = /^(RE:|AW:)/i.test(subject.trim());

// Strip thread for replies, keep full body for forwards
const cleanBody = stripSig(stripThread(bodyText, isForward));
const finalBody = cleanBody.length >= 20 ? cleanBody : [bodyPreview, bodyText].filter(Boolean).join('\n\n');

// Dedup check
const store = $getWorkflowStaticData('global');
if (!Array.isArray(store.processedEmails)) store.processedEmails = [];
const msgId = msg.id || '';
const internetMsgId = msg.internetMessageId || '';
const uniqueKey = internetMsgId || msgId;
const alreadyProcessed = uniqueKey ? store.processedEmails.includes(uniqueKey) : false;

// Extract original sender from forwarded headers
const allText = [subject, bodyPreview, bodyText].join('\n');
const senderPatterns = [
  /(?:van|from|von):\s.*?<([^>]+@[^>]+)>/i,
  /(?:van|from|von):\s.*?([a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,})/i
];
let origSender = '';
for (const p of senderPatterns) {
  const m = allText.match(p);
  if (m?.[1]) { origSender = m[1].toLowerCase(); break; }
}
if (!origSender) origSender = email(msg.from) || email(msg.sender) || '';

// Detect feedback from colleagues
const isFeedback = /feedback/i.test(subject) && (email(msg.from) || '').endsWith('@agroworld.nl');

return {json: {
  ...msg,
  source_type: 'email',
  message_id: msgId,
  email_id: msgId,
  internet_message_id: internetMsgId,
  unique_key: uniqueKey,
  has_attachments: !!msg.hasAttachments,
  from_address: email(msg.from),
  sender_address: email(msg.sender),
  original_sender_address: origSender,
  to_addresses: (msg.toRecipients || []).map(email).filter(Boolean),
  mail_subject: subject,
  mail_body_preview: bodyPreview,
  mail_body_html: bodyHtml,
  mail_text: finalBody.slice(0, 20000),
  received_at: msg.receivedDateTime || '',
  already_processed: alreadyProcessed,
  skip_processing: alreadyProcessed,
  is_forward: isForward,
  is_feedback: isFeedback,
}};

return {json: {...$json,
  processing_mode: 'mail_only',
  attachment_name: '', attachment_extension: '', attachment_mime_type: '',
  extracted_attachment_text: '',
  attachment_summary: 'Geen bijlage. AI analyseert uitsluitend de mailinhoud.',
}};

const upstream = $('Normalize Email').item.json;
const name = String($json.name || $json.filename || '').trim();
const ext = (name.match(/\.([^.]+)$/)?.[1] || '').toLowerCase();
return {json: {
  ...upstream,
  attachment_id: $json.id || '',
  attachment_name: name,
  attachment_extension: ext,
  attachment_mime_type: $json.contentType || '',
  attachment_size: $json.size || 0,
}};

const meta = $('Prep Attachment Meta').item.json;
const xmlData = $json.xmlData || $json;
const raw = typeof xmlData === 'string' ? xmlData : JSON.stringify(xmlData);

// Try to pre-parse VFPData for cleaner AI input
let text = raw;
try {
  if (/<VFPData/i.test(raw)) {
    const recs = [];
    const re = /<query>([\s\S]*?)<\/query>/gi;
    let m;
    while ((m = re.exec(raw)) !== null) {
      const fields = {};
      const fr = /<([A-Za-z0-9_:-]+)>([\s\S]*?)<\/\1>/g;
      let fm;
      while ((fm = fr.exec(m[1])) !== null) {
        const v = fm[2].replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&').replace(/<!\[CDATA\[/,'').replace(/\]\]>/,'').trim();
        if (v) fields[fm[1]] = v;
      }
      if (Object.keys(fields).length > 0) recs.push(fields);
    }
    if (recs.length > 0) {
      text = JSON.stringify(recs, null, 1);
    }
  }
} catch(e) {
  // Fall back to raw
}

return {json: {
  ...meta,
  processing_mode: 'attachment_xml',
  extracted_attachment_text: String(text || '').slice(0, 120000),
  attachment_summary: 'XML geparseerd (' + (text.length < raw.length ? 'gestructureerd' : 'raw') + ').',
}};

const meta = $('Prep Attachment Meta').item.json;
const payload = $json.text || $json.data || $json;
const text = typeof payload === 'string' ? payload : JSON.stringify(payload);
return {json: {
  ...meta,
  processing_mode: 'attachment_pdf',
  extracted_attachment_text: String(text || '').slice(0, 120000),
  attachment_summary: 'PDF bijlage geextraheerd voor AI interpretatie.',
}};

const meta = $('Prep Attachment Meta').item.json;
const items = $input.all();
const payload = items.map(i => i.json);
const text = JSON.stringify(payload, null, 2);
return [{json: {
  ...meta,
  processing_mode: 'attachment_xlsx',
  extracted_attachment_text: String(text || '').slice(0, 120000),
  attachment_summary: 'Excel bijlage (XLSX/XLS) geextraheerd als JSON rijen voor AI interpretatie.',
}}];

const meta = $('Prep Attachment Meta').item.json;
const bin = $binary || {};
const key = Object.keys(bin)[0];
let text = '';
if (key) { try { text = Buffer.from(bin[key].data, 'base64').toString('utf8').slice(0,120000); } catch(e){} }
return {json: {
  ...meta,
  processing_mode: 'attachment_text',
  extracted_attachment_text: text,
  attachment_summary: 'Tekst bijlage geextraheerd.',
}};

const meta = $('Prep Attachment Meta').item.json;
return {json: {
  ...meta,
  processing_mode: 'attachment_image',
  extracted_attachment_text: 'Afbeelding bijlage. Extensie: ' + meta.attachment_extension + '. Naam: ' + meta.attachment_name + '. AI gebruikt mailcontext.',
  attachment_summary: 'Afbeelding bijlage zonder OCR.',
}};

const meta = $('Prep Attachment Meta').item.json;
const bin = $binary || {};
const key = Object.keys(bin)[0];
const b = key ? bin[key] : null;
let hexPreview = '';
if (b?.data) { try { hexPreview = Buffer.from(b.data,'base64').subarray(0,32).toString('hex'); } catch(e){} }
return {json: {
  ...meta,
  processing_mode: 'attachment_' + (meta.attachment_extension || 'unknown'),
  extracted_attachment_text: 'Onbekend bestandstype. Extensie: ' + meta.attachment_extension + '. Mime: ' + meta.attachment_mime_type,
  attachment_summary: 'Generiek onbekend bijlagetype.',
}};

const items = $input.all();
if (!items.length) return [{json: {attachment_count: 0, processing_mode: 'mail_only'}}];
const first = items[0].json || {};
const attachments = items.map(({json:j}) => ({
  name: j.attachment_name || '',
  extension: j.attachment_extension || '',
  processing_mode: j.processing_mode || '',
  summary: j.attachment_summary || '',
  extracted_text: String(j.extracted_attachment_text || '').slice(0, 15000),
}));
const combinedText = attachments.map((a,i) =>
  '--- BIJLAGE ' + (i+1) + ': ' + a.name + ' (' + a.extension + ') ---\n' + a.summary + '\n' + a.extracted_text
).join('\n\n').slice(0, 120000);
return [{json: {
  ...first,
  attachment_count: attachments.length,
  processing_mode: attachments.length === 1 ? attachments[0].processing_mode : 'mail_with_multiple_attachments',
  extracted_attachment_text: combinedText,
  attachment_summary: attachments.map(a=>a.name + ': ' + a.summary).join('\n'),
}}];

const d = $json;
const store = $getWorkflowStaticData('global');
const memory = store.qargoMailMemory || [];
const customers = store.knownCustomers || {};
const customerSamples = store.customerSamples || {};
const learnings = store.aiLearnings || [];

const senderDomain = String(d.original_sender_address || d.from_address || '').split('@').pop().toLowerCase();

// Recent activity summary
const recentMemory = memory.slice(-5).map(m =>
  (m.saved_at || '').slice(5, 10) + ' ' + (m.sender_domain || '?') + ':' + (m.operation || '?')
).join('\n');

// Per-sender successful sample (last 1 successful Qargo payload from this sender)
const senderSample = customerSamples[senderDomain] || null;
let sampleText = '';
if (senderSample && senderSample.payload) {
  try {
    const compact = {
      customer: senderSample.payload.customer?.name,
      order_identifier: senderSample.payload.order_identifier,
      customer_reference_number: senderSample.payload.customer_reference_number,
      pickup: senderSample.payload.consignments?.[0]?.pickup_stop?.location,
      delivery: senderSample.payload.consignments?.[0]?.delivery_stop?.location,
      goods: senderSample.payload.consignments?.[0]?.goods?.[0],
    };
    sampleText = 'LAATSTE GOED VERWERKTE ORDER VAN DEZE AFZENDER:\n' + JSON.stringify(compact, null, 1);
  } catch (e) {}
}

// Learnings from feedback mails (last 5)
const learningsText = learnings.slice(-5).map(l => l.date + ': ' + (l.feedback || '').slice(0, 120)).join('\n');

return {
  json: {
    ...d,
    memory_context: recentMemory || '',
    known_customers: Object.keys(customers).join(',') || '',
    memory_count: memory.length,
    ai_learnings: learningsText,
    sender_sample: sampleText,
    sender_domain: senderDomain,
  }
};

const d = $json;
function clean(s) {
  return String(s || '')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
    .replace(/\uFEFF/g, '').replace(/\u0000/g, '');
}
const isStructured = ['attachment_xml', 'attachment_xlsx'].includes(d.processing_mode);
const attachLimit = isStructured ? 18000 : 6000;
const mailLimit = 1500;
const mailText = clean(d.mail_text || d.mail_body_preview || '').slice(0, mailLimit);
const attachText = clean(d.extracted_attachment_text || '').slice(0, attachLimit);

const memorySection = d.memory_count > 0
  ? `\n## RECENT\n${clean(d.memory_context || '').slice(0, 300)}` : '';
const sampleSection = d.sender_sample
  ? `\n## VORIGE GELUKTE ORDER VAN DEZE AFZENDER (gebruik als referentie voor structuur)\n${clean(d.sender_sample).slice(0, 2000)}` : '';
const learningsText = clean(d.ai_learnings || '').split('\n').slice(-5).join('\n');

const userPrompt = `Van: ${clean(d.original_sender_address || d.from_address || '?')}
Onderwerp: ${clean(d.mail_subject || '?')}
Bijlage: ${clean(d.attachment_name || 'geen')} (${d.attachment_extension || '-'})${memorySection}${sampleSection}

## LESSEN UIT FEEDBACK
${learningsText || 'geen'}

## MAIL
${mailText || '(leeg)'}

## BIJLAGE
${attachText || '(geen)'}

BESCHIKBARE TOOLS:
- structured_parser_tool: parse XML/JSON/XLSX gestructureerd
- address_lookup: zoek ontbrekende adressen op via OpenStreetMap (gebruik wanneer adres/postcode/land ontbreekt)`;

return { json: { ...d, ai_user_prompt: userPrompt } };

function clean(v) { return String(v == null ? '' : v).trim(); }
function toNum(v) { const n = parseFloat(String(v || '').replace(',', '.').replace(/[^\d.-]/g, '')); return isFinite(n) ? n : 0; }

function normDate(v) {
  const t = clean(v).replace(/\./g, '-').replace(/\//g, '-');
  if (!t) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(t)) return t;
  const dmy = t.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  if (dmy) return `${dmy[3]}-${dmy[2]}-${dmy[1]}`;
  // Try Date parsing as fallback
  try { const d = new Date(t); if (!isNaN(d)) return d.toISOString().slice(0, 10); } catch(e) {}
  return t;
}

function mapTemp(v) {
  const t = clean(v).toLowerCase();
  if (!t) return 'Ambient ( Geen Temp)';
  if (t.includes('ultrafrisch') || t.includes('ultra fresh')) return 'Ultra Fresh (0C / 3C)';
  if (t.includes('tiefk') || t.includes('frozen') || t.includes('vries')) return 'Frozen (-18C / -30C)';
  if (t.includes('frisch') || t.includes('fresh') || t.includes('gekoeld')) return 'Fresh (4C / 7C)';
  if (t.includes('thermo')) return 'Thermo (8C / 20C)';
  const m = t.match(/-?\d+(\.\d+)?/);
  if (!m) return 'Ambient ( Geen Temp)';
  const n = parseFloat(m[0]);
  if (n <= -18) return 'Frozen (-18C / -30C)';
  if (n >= 0 && n <= 3) return 'Ultra Fresh (0C / 3C)';
  if (n >= 4 && n <= 7) return 'Fresh (4C / 7C)';
  if (n >= 8 && n <= 20) return 'Thermo (8C / 20C)';
  return 'Ambient ( Geen Temp)';
}

function mapPkg(v) {
  const k = clean(v).toUpperCase();
  const map = {
    'EURO':'EURO','EUR':'EURO','EP':'EURO','PLT':'EURO','HOLZ':'EURO',
    'CHEP':'CHEP','DOLAV':'DOLAV','BLOK':'BLOK',
    'BB':'Big Block','BIGBOX':'Big Block','BIG BLOCK':'Big Block',
    'KUNST':'EWP','EWP':'EWP','KUNSTSTOFF':'EWP',
    'ONEWAY':'ONEWAY ( Eenmalige pallet)',
    'PAL':'Pallet','PALLET':'Pallet',
    'H1':'H1','CBL 11':'CBL 11','CBL 17':'CBL 17','CKW':'CKW'
  };
  return map[k] || v || 'EURO';
}

function tryParse(t) { try { return JSON.parse(t); } catch(e) { return null; } }

function parseVFP(xml) {
  if (!/<VFPData/i.test(xml)) return null;
  const recs = [];
  const re = /<query>([\s\S]*?)<\/query>/gi;
  let m;
  while ((m = re.exec(xml)) !== null) {
    const fields = {};
    const fr = /<([A-Za-z0-9_:-]+)>([\s\S]*?)<\/\1>/g;
    let fm;
    while ((fm = fr.exec(m[1])) !== null) {
      fields[fm[1]] = fm[2].replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&').replace(/<!\[CDATA\[/, '').replace(/\]\]>/, '').trim();
    }
    if (Object.keys(fields).length > 0) recs.push(fields);
  }
  if (!recs.length) return null;

  // Group by order number
  const grouped = {};
  for (const r of recs) {
    const nr = r.so_hdr_ord_nr || 'UNKNOWN';
    if (!grouped[nr]) grouped[nr] = [];
    grouped[nr].push(r);
  }

  return Object.entries(grouped).map(([nr, rows]) => {
    const f = rows[0];
    return {
      order_identifier: nr,
      customer_reference_number: f.so_hdr_comment1 || nr,
      pickup_date: normDate(f.c9_load || f.vm_load),
      delivery_date: normDate(f.c9_unload || f.vm_unload),
      pickup_location: f.c9_coldoms || f.vm_coldoms || '',
      delivery_name: f.acct_name || f.c9_invacct || '',
      delivery_address: f.address1 || '',
      delivery_city: f.city || '',
      delivery_country: f.country || '',
      delivery_postal: f.post_code || '',
      goods: rows.map(r => ({
        description: [r.art_code, r.art_desc1].filter(Boolean).join(' '),
        colli: toNum(r.tot_colli),
        weight: toNum(r.ord_qty),
        packaging: mapPkg(r.c9_tpl || r.vm_tpl),
        temperature: mapTemp(r.article_comment1 || r.so_dtl_temperature || r.vm_temp),
      })),
      note: f.c9_lco || f.vm_lco || '',
      reference: f.c9_rn || f.t_recid || '',
      pallets: toNum(f.c9_ap || f.vm_ap),
    };
  });
}

// Main entry
var inp = typeof query === 'string' ? tryParse(query) || {attachment_text: query} : (query || {});
var txt = clean(inp.attachment_text);

if (/<VFPData/i.test(txt)) {
  var vfp = parseVFP(txt);
  if (vfp) return JSON.stringify(vfp);
}

var parsed = tryParse(txt);
if (parsed && typeof parsed === 'object') return JSON.stringify(parsed);

return JSON.stringify({raw_text: txt.slice(0, 8000), note: 'Niet structureel parseerbaar - AI gebruikt ruwe tekst'});

const raw = String($json.output || $json.text || $json.response || '').trim();
const upstream = $json || {};

let parsed = null;
const patterns = [/```json\s*([\s\S]*?)```/, /```\s*([\s\S]*?)```/, /([\[{][\s\S]*[\]}])/];

for (const pattern of patterns) {
  const match = raw.match(pattern);
  if (!match) continue;
  let jsonStr = (match[1] || match[0]).trim();

  try { const c = JSON.parse(jsonStr); if (c && typeof c === 'object') { parsed = c; break; } } catch(e) {}

  // Truncated array recovery: extract all complete objects
  if (jsonStr.startsWith('[')) {
    const objects = [];
    let depth = 0, start = -1;
    for (let i = 0; i < jsonStr.length; i++) {
      if (jsonStr[i] === '{') { if (depth === 0) start = i; depth++; }
      if (jsonStr[i] === '}') { depth--; if (depth === 0 && start >= 0) { objects.push(jsonStr.slice(start, i + 1)); start = -1; } }
    }
    if (objects.length > 0) {
      try { parsed = objects.map(o => JSON.parse(o)); break; } catch(e) {}
    }
  }
}

if (!parsed) {
  try { const c = JSON.parse(raw); if (c && typeof c === 'object') parsed = c; } catch(e) {}
}

if (!parsed) {
  return [{json: {
    ...upstream,
    classification: { operation: 'MANUAL_REVIEW', manual_review: true, confidence: 0,
      reason: 'AI gaf geen geldige JSON. Raw: ' + raw.slice(0, 500),
      customer_flow: '', is_new_customer: false, new_customer_domain: '', new_customer_name: '' },
    qargo_payload: '', normalized_order: {order_identifier: '', customer_name: '', missing_fields: ['all']},
    ai_raw_output: raw.slice(0, 2000),
  }}];
}

function sanitize(obj) {
  if (obj === null || obj === undefined) return '';
  if (typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(sanitize);
  const result = {};
  const numKeys = new Set(['quantity', 'total_weight_kg', 'colli', 'confidence']);
  for (const [key, val] of Object.entries(obj)) {
    if (val === null || val === undefined) { result[key] = numKeys.has(key) ? 0 : ''; }
    else { result[key] = sanitize(val); }
  }
  return result;
}

function str(val) {
  if (val === null || val === undefined) return '';
  if (typeof val === 'string') return val;
  if (typeof val === 'object') { try { return JSON.stringify(val); } catch(e) {} }
  return String(val);
}

const orders = Array.isArray(parsed) ? parsed : [parsed];
return orders.map((order, index) => {
  const s = sanitize(order);
  const cls = {...(s.classification || {})};

  cls.reason = str(cls.reason);
  cls.customer_flow = str(cls.customer_flow);
  cls.new_customer_domain = str(cls.new_customer_domain);
  cls.new_customer_name = str(cls.new_customer_name);
  cls.operation = str(cls.operation) || 'MANUAL_REVIEW';
  if (typeof cls.confidence === 'number' && cls.confidence < 0.5 && cls.operation !== 'IGNORE') {
    cls.operation = 'MANUAL_REVIEW'; cls.manual_review = true;
  }
  cls.manual_review = cls.manual_review || cls.operation === 'MANUAL_REVIEW';
  cls.is_new_customer = cls.is_new_customer || false;
  if (cls.is_new_customer && (cls.confidence || 0) < 0.8) cls.is_new_customer = false;

  const payload = s.qargo_payload;
  if (payload && payload.consignments) {
    for (const c of payload.consignments) {
      if (c.goods) {
        for (const g of c.goods) {
          if ((!g.quantity || g.quantity === 0) && g.total_weight_kg > 0) {
            g.quantity = Math.ceil(g.total_weight_kg / 700);
          }
        }
      }
      // Empty date: DELETE the field so Qargo doesn't reject it
      if (c.delivery_stop && (!c.delivery_stop.date || c.delivery_stop.date === '')) {
        delete c.delivery_stop.date;
        if (!payload.service_level) payload.service_level = {"code": "AB"};
      }
      if (c.pickup_stop && (!c.pickup_stop.date || c.pickup_stop.date === '')) {
        delete c.pickup_stop.date;
      }
      if (c.pickup_stop) delete c.pickup_stop.duration;
      // Remove empty time_windows (if AI sent them without actual times)
      if (c.pickup_stop?.time_window) {
        if (!c.pickup_stop.time_window.start_time && !c.pickup_stop.time_window.end_time) {
          delete c.pickup_stop.time_window;
        }
      }
      if (c.delivery_stop) delete c.delivery_stop.duration;
      if (c.delivery_stop?.time_window) {
        if (!c.delivery_stop.time_window.start_time && !c.delivery_stop.time_window.end_time) {
          delete c.delivery_stop.time_window;
        }
      }
    }
  }

  // Fix service_level format: always {"code": "AB"}, never {"name": "AB"}
  if (payload && payload.service_level) {
    if (typeof payload.service_level === 'string') {
      payload.service_level = {"code": payload.service_level};
    } else if (payload.service_level.name && !payload.service_level.code) {
      payload.service_level = {"code": payload.service_level.name};
      delete payload.service_level.name;
    }
  }

