          city:        String(pick(row, 'EmpOrt', 'Ort', 'Stadt')).trim(),
          country,
        },
      },
      goods: [{
        quantity: qty || (weight ? Math.ceil(weight / 700) : 0),
        total_weight_kg: weight,
        description: desc,
        packaging_type: { name: pkg },
        custom_fields: { colli: 0, temperature1: temp },
      }],
    }],
  };

  out.push({
    json: {
      ...d,
      classification: {
        operation,
        manual_review: missing.length > 0,
        confidence: missing.length ? 0.7 : 1.0,
        reason: missing.length ? `Tönnies mapper: mist ${missing.join(',')}` : `Tönnies mapper OK (${kommNr})`,
        customer_flow: 'tonnies_deterministic',
        is_new_customer: false,
        new_customer_domain: '',
        new_customer_name: '',
      },
      qargo_payload: payload,
      normalized_order: {
        order_identifier: kommNr,
        customer_name: customer,
        pickup_date: pickupDate,
        delivery_date: delDate,
        pickup_location: `${pickupLoc.name}, ${pickupLoc.city}`,
        delivery_location: `${payload.consignments[0].delivery_stop.location.name}, ${payload.consignments[0].delivery_stop.location.city}`,
        missing_fields: missing,
      },
      order_index: orderIdx++,
      total_orders_in_mail: 0, // filled after loop
      ai_raw_output: '',
      mapper_used: 'tonnies_v1',
    }
  });
}

// Fill total count
for (const item of out) item.json.total_orders_in_mail = out.length;

// If no rows matched -> fall back to AI by returning nothing and letting router catch it?
// Simpler: return a single manual_review item so nothing is silently dropped
if (out.length === 0) {
  return [{
    json: {
      ...d,
      classification: {
        operation: 'MANUAL_REVIEW',
        manual_review: true,
        confidence: 0,
        reason: 'Tönnies mapper vond geen rijen met KommNr. Handmatig controleren.',
        customer_flow: 'tonnies_deterministic_empty',
        is_new_customer: false,
      },
      qargo_payload: '',
      normalized_order: { order_identifier: '', customer_name: 'Tönnies', missing_fields: ['all'] },
      ai_raw_output: '',
      mapper_used: 'tonnies_v1_empty',
    }
  }];
}

return out;

// Address lookup via OpenStreetMap Nominatim (free, no auth)
// Input: JSON with {query: "...search text..."} or plain text
// Output: JSON with resolved address or empty
async function lookup(q) {
  const url = 'https://nominatim.openstreetmap.org/search?format=json&limit=1&addressdetails=1&q=' + encodeURIComponent(q);
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'User-Agent': 'AgroWorld-OrderIntake/1.0 (it@agroworld.nl)' },
    json: true,
  });
  if (!Array.isArray(res) || res.length === 0) return null;
  const r = res[0];
  const a = r.address || {};
  return {
    name: a.amenity || a.shop || a.building || '',
    address: [a.road, a.house_number].filter(Boolean).join(' '),
    postal_code: a.postcode || '',
    city: a.city || a.town || a.village || a.municipality || '',
    country: (a.country_code || '').toUpperCase(),
    latitude: parseFloat(r.lat),
    longitude: parseFloat(r.lon),
    display_name: r.display_name,
  };
}

let q = '';
try {
  const parsed = typeof query === 'string' ? JSON.parse(query) : query;
  q = parsed?.query || parsed?.q || (typeof parsed === 'string' ? parsed : '');
} catch (e) {
  q = typeof query === 'string' ? query : '';
}
if (!q || q.length < 3) return JSON.stringify({error: 'Geef een zoekterm van minimaal 3 tekens'});

try {
  const result = await lookup.call(this, q);
  return JSON.stringify(result || {error: 'Niet gevonden'});
} catch (e) {
  return JSON.stringify({error: String(e.message || e)});
}
